{"content": """"文件格式转换器核心逻辑

符合百度团队规范：
- 配置文件：只用 TOML（tomllib/tomli_w）
- 错误处理：Result 模式，不用裸 try/except
- 日志：只用 loguru
"""

import json
import tomllib  # Python 3.11+ 标准库
from pathlib import Path
from typing import Any

import tomli_w
import yaml
from loguru import logger
from result import Result, Ok, Err

from constants import (
    FORMAT_JSON,
    FORMAT_YAML,
    FORMAT_TOML,
    SUPPORTED_FORMATS,
    FILE_EXTENSION_MAP,
    ALTERNATIVE_EXTENSIONS,
    DEFAULT_ENCODING,
    MAX_FILE_SIZE_BYTES,
    MAX_FILE_SIZE_MB,
    DEFAULT_INDENT,
    LOG_MSG_FILE_READ_START,
    LOG_MSG_FILE_READ_SUCCESS,
    LOG_MSG_FILE_READ_ERROR,
    LOG_MSG_FILE_WRITE_START,
    LOG_MSG_FILE_WRITE_SUCCESS,
    LOG_MSG_FILE_WRITE_ERROR,
    LOG_MSG_CONVERT_START,
    LOG_MSG_CONVERT_SUCCESS,
    LOG_MSG_CONVERT_ERROR,
    LOG_MSG_FORMAT_DETECTED,
    LOG_MSG_FORMAT_DETECTION_FAILED,
    ERROR_MSG_FILE_NOT_FOUND,
    ERROR_MSG_FILE_TOO_LARGE,
    ERROR_MSG_FILE_READ_FAILED,
    ERROR_MSG_FILE_WRITE_FAILED,
    ERROR_MSG_FILE_ENCODING_ERROR,
    ERROR_MSG_UNSUPPORTED_FORMAT,
    ERROR_MSG_INVALID_JSON,
    ERROR_MSG_INVALID_YAML,
    ERROR_MSG_INVALID_TOML,
    ERROR_MSG_PARSE_FAILED,
    ERROR_MSG_SERIALIZE_FAILED,
    ERROR_MSG_CONVERSION_FAILED,
    ERROR_MSG_DATA_LOSS_WARNING,
)
from models import DataSchema, SchemaValidator


# ==================== 格式转换器 ====================

class FormatConverter:
    """文件格式转换器（使用 Result 模式）"""

    def __init__(
        self,
        pretty_print: bool = True,
        indent: int = DEFAULT_INDENT,
        encoding: str = DEFAULT_ENCODING,
    ) -> None:
        self.pretty_print = pretty_print
        self.indent = indent
        self.encoding = encoding

    # ==================== 文件读取 ====================

    def read_file(self, path: str | Path) -> Result[str, str]:
        """读取文件内容（带大小检查）"""
        path = Path(path)

        logger.debug(LOG_MSG_FILE_READ_START.format(path=path))

        # 检查文件是否存在
        if not path.exists():
            error = ERROR_MSG_FILE_NOT_FOUND.format(path=path)
            logger.error(LOG_MSG_FILE_READ_ERROR.format(path=path, error=error))
            return Err(error)

        # 检查文件大小
        file_size = path.stat().st_size
        if file_size > MAX_FILE_SIZE_BYTES:
            error = ERROR_MSG_FILE_TOO_LARGE.format(
                size=file_size,
                max_size=MAX_FILE_SIZE_BYTES,
            )
            logger.error(LOG_MSG_FILE_READ_ERROR.format(path=path, error=error))
            return Err(error)

        # 读取文件
        try:
            content = path.read_text(encoding=self.encoding)
            logger.debug(LOG_MSG_FILE_READ_SUCCESS.format(
                path=path,
                size=file_size,
            ))
            return Ok(content)
        except UnicodeDecodeError as e:
            error = ERROR_MSG_FILE_ENCODING_ERROR.format(error=str(e))
            logger.error(LOG_MSG_FILE_READ_ERROR.format(path=path, error=error))
            return Err(error)
        except OSError as e:
            error = ERROR_MSG_FILE_READ_FAILED.format(error=str(e))
            logger.error(LOG_MSG_FILE_READ_ERROR.format(path=path, error=error))
            return Err(error)

    def write_file(self, path: str | Path, content: str) -> Result[int, str]:
        """写入文件内容"""
        path = Path(path)

        logger.debug(LOG_MSG_FILE_WRITE_START.format(path=path))

        try:
            # 创建父目录（如果不存在）
            path.parent.mkdir(parents=True, exist_ok=True)

            # 写入文件
            path.write_text(content, encoding=self.encoding)

            file_size = path.stat().st_size
            logger.debug(LOG_MSG_FILE_WRITE_SUCCESS.format(
                path=path,
                size=file_size,
            ))
            return Ok(file_size)
        except OSError as e:
            error = ERROR_MSG_FILE_WRITE_FAILED.format(error=str(e))
            logger.error(LOG_MSG_FILE_WRITE_ERROR.format(path=path, error=error))
            return Err(error)

    # ==================== 格式检测 ====================

    def detect_format(self, path: str | Path) -> Result[str, str]:
        """从文件扩展名检测格式"""
        path = Path(path)
        extension = path.suffix.lower()

        if extension in ALTERNATIVE_EXTENSIONS:
            format_name = ALTERNATIVE_EXTENSIONS[extension]
            logger.debug(LOG_MSG_FORMAT_DETECTED.format(format=format_name))
            return Ok(format_name)

        error = LOG_MSG_FORMAT_DETECTION_FAILED.format(extension=extension)
        logger.warning(error)
        return Err(error)

    # ==================== 解析（字符串 → 字典） ====================

    def parse_json(self, content: str) -> Result[dict[str, Any], str]:
        """解析 JSON 字符串"""
        try:
            data = json.loads(content)
            if not isinstance(data, dict):
                return Err("JSON root must be an object, not array or primitive")
            return Ok(data)
        except json.JSONDecodeError as e:
            error = ERROR_MSG_INVALID_JSON.format(error=str(e))
            return Err(error)

    def parse_yaml(self, content: str) -> Result[dict[str, Any], str]:
        """解析 YAML 字符串"""
        try:
            data = yaml.safe_load(content)
            if not isinstance(data, dict):
                return Err("YAML root must be an object, not array or primitive")
            return Ok(data)
        except yaml.YAMLError as e:
            error = ERROR_MSG_INVALID_YAML.format(error=str(e))
            return Err(error)

    def parse_toml(self, content: str) -> Result[dict[str, Any], str]:
        """解析 TOML 字符串（使用 tomllib）"""
        try:
            data = tomllib.loads(content)
            return Ok(data)
        except tomllib.TOMLDecodeError as e:
            error = ERROR_MSG_INVALID_TOML.format(error=str(e))
            return Err(error)

    def parse(self, content: str, format_name: str) -> Result[dict[str, Any], str]:
        """解析指定格式的字符串"""
        if format_name not in SUPPORTED_FORMATS:
            return Err(ERROR_MSG_UNSUPPORTED_FORMAT.format(
                format=format_name,
                supported=", ".join(SUPPORTED_FORMATS),
            ))

        match format_name:
            case "json":
                return self.parse_json(content)
            case "yaml":
                return self.parse_yaml(content)
            case "toml":
                return self.parse_toml(content)
            case _:
                return Err(ERROR_MSG_PARSE_FAILED.format(
                    format=format_name,
                    error="Unknown format",
                ))

    # ==================== 序列化（字典 → 字符串） ====================

    def serialize_json(self, data: dict[str, Any]) -> Result[str, str]:
        """序列化为 JSON 字符串"""
        try:
            if self.pretty_print:
                content = json.dumps(
                    data,
                    indent=self.indent,
                    ensure_ascii=False,
                    sort_keys=False,
                )
            else:
                content = json.dumps(data, ensure_ascii=False)
            return Ok(content)
        except (TypeError, ValueError) as e:
            error = ERROR_MSG_SERIALIZE_FAILED.format(format=FORMAT_JSON, error=str(e))
            return Err(error)

    def serialize_yaml(self, data: dict[str, Any]) -> Result[str, str]:
        """序列化为 YAML 字符串"""
        try:
            content = yaml.dump(
                data,
                allow_unicode=True,
                default_flow_style=False,
                sort_keys=False,
                indent=self.indent,
            )
            return Ok(content)
        except yaml.YAMLError as e:
            error = ERROR_MSG_SERIALIZE_FAILED.format(format=FORMAT_YAML, error=str(e))
            return Err(error)

    def serialize_toml(self, data: dict[str, Any]) -> Result[str, str]:
        """序列化为 TOML 字符串（使用 tomli_w）"""
        try:
            # TOML 不支持 null 值，需要先清理
            cleaned_data = self._clean_data_for_toml(data)
            content = tomli_w.dumps(cleaned_data)
            return Ok(content)
        except (TypeError, ValueError) as e:
            error = ERROR_MSG_SERIALIZE_FAILED.format(format=FORMAT_TOML, error=str(e))
            return Err(error)

    def serialize(self, data: dict[str, Any], format_name: str) -> Result[str, str]:
        """序列化为指定格式的字符串"""
        if format_name not in SUPPORTED_FORMATS:
            return Err(ERROR_MSG_UNSUPPORTED_FORMAT.format(
                format=format_name,
                supported=", ".join(SUPPORTED_FORMATS),
            ))

        match format_name:
            case "json":
                return self.serialize_json(data)
            case "yaml":
                return self.serialize_yaml(data)
            case "toml":
                return self.serialize_toml(data)
            case _:
                return Err(ERROR_MSG_SERIALIZE_FAILED.format(
                    format=format_name,
                    error="Unknown format",
                ))

    # ==================== 格式转换 ====================

    def convert(
        self,
        source_format: str,
        target_format: str,
        content: str,
        schema: DataSchema | None = None,
    ) -> Result[tuple[str, list[str]], str]:
        """
        转换格式

        Returns:
            Ok((转换后的内容, 警告列表)) 或 Err(错误消息)
        """
        logger.info(LOG_MSG_CONVERT_START.format(
            source_format=source_format,
            target_format=target_format,
        ))

        warnings: list[str] = []

        # 1. 解析源格式
        parse_result = self.parse(content, source_format)
        match parse_result:
            case Err(error):
                logger.error(LOG_MSG_CONVERT_ERROR.format(
                    source_format=source_format,
                    target_format=target_format,
                    error=error,
                ))
                return Err(ERROR_MSG_CONVERSION_FAILED.format(error=error))
            case Ok(data):
                pass

        # 2. Schema 验证（如果提供）
        if schema is not None:
            validator = SchemaValidator(schema)
            validation_result = validator.validate(data)
            match validation_result:
                case Err(error):
                    logger.error(LOG_MSG_CONVERT_ERROR.format(
                        source_format=source_format,
                        target_format=target_format,
                        error=error,
                    ))
                    return Err(ERROR_MSG_CONVERSION_FAILED.format(error=error))
                case Ok(_):
                    pass

        # 3. 检查数据兼容性警告
        if target_format == FORMAT_TOML:
            if self._has_null_values(data):
                warnings.append(ERROR_MSG_DATA_LOSS_WARNING)

        # 4. 序列化目标格式
        serialize_result = self.serialize(data, target_format)
        match serialize_result:
            case Err(error):
                logger.error(LOG_MSG_CONVERT_ERROR.format(
                    source_format=source_format,
                    target_format=target_format,
                    error=error,
                ))
                return Err(ERROR_MSG_CONVERSION_FAILED.format(error=error))
            case Ok(output):
                logger.info(LOG_MSG_CONVERT_SUCCESS.format(
                    source_format=source_format,
                    target_format=target_format,
                ))
                return Ok((output, warnings))

    def convert_file(
        self,
        input_path: str | Path,
        output_path: str | Path,
        source_format: str | None = None,
        target_format: str | None = None,
        schema: DataSchema | None = None,
    ) -> Result[list[str], str]:
        """
        转换文件格式

        Returns:
            Ok(警告列表) 或 Err(错误消息)
        """
        input_path = Path(input_path)
        output_path = Path(output_path)

        # 自动检测源格式
        if source_format is None:
            detect_result = self.detect_format(input_path)
            match detect_result:
                case Err(error):
                    return Err(error)
                case Ok(fmt):
                    source_format = fmt

        # 自动检测目标格式
        if target_format is None:
            detect_result = self.detect_format(output_path)
            match detect_result:
                case Err(error):
                    return Err(error)
                case Ok(fmt):
                    target_format = fmt

        # 读取输入文件
        read_result = self.read_file(input_path)
        match read_result:
            case Err(error):
                return Err(error)
            case Ok(content):
                pass

        # 转换格式
        convert_result = self.convert(source_format, target_format, content, schema)
        match convert_result:
            case Err(error):
                return Err(error)
            case Ok((output_content, warnings)):
                pass

        # 写入输出文件
        write_result = self.write_file(output_path, output_content)
        match write_result:
            case Err(error):
                return Err(error)
            case Ok(_):
                return Ok(warnings)

    # ==================== 辅助方法 ====================

    def _has_null_values(self, data: Any) -> bool:
        """检查数据中是否包含 null 值"""
        if data is None:
            return True

        if isinstance(data, dict):
            return any(self._has_null_values(v) for v in data.values())

        if isinstance(data, list):
            return any(self._has_null_values(item) for item in data)

        return False

    def _clean_data_for_toml(self, data: Any) -> Any:
        """清理数据以适配 TOML（移除 null 值）"""
        if isinstance(data, dict):
            return {
                k: self._clean_data_for_toml(v)
                for k, v in data.items()
                if v is not None
            }

        if isinstance(data, list):
            return [
                self._clean_data_for_toml(item)
                for item in data
                if item is not None
            ]

        return data
